import { SAMPLE_RATE } from './constants';

// indices for the shared array

// (0-3 are reserved for the gain values for tracks 1-4)
const TAPE_STATE_TIME_DIV = 4;
const TAPE_STATE_TEMPO = 5;
const TAPE_STATE_SELECTED_TRACK_IDX = 6;
const TAPE_STATE_NUM_CLIPS = 7;
const TAPE_STATE_PLAYHEAD = 8;
const TAPE_STATE_RECORDING = 9;
const TAPE_STATE_PLAYING_DIRECTION = 10;
const TAPE_STATE_LOOP_ON = 11;
const TAPE_STATE_LOOP_IN_POINT = 12;
const TAPE_STATE_LOOP_OUT_POINT = 13;
const TAPE_STATE_CLICK_ON = 14;
const TAPE_STATE_METRONOME_STICK_DIRECTION = 15;
const TAPE_STATE_SPEED = 16;
const TAPE_STATE_NEXT_CLIP_SAMPLE_IDX = 17;
// Important: don't use the following indices for anything b/c that's "next sample idx" works.
// const TAPE_STATE_NEXT_CLIP_SAMPLE_IDX_TRACK_1 = 17;
// const TAPE_STATE_NEXT_CLIP_SAMPLE_IDX_TRACK_2 = 18;
// const TAPE_STATE_NEXT_CLIP_SAMPLE_IDX_TRACK_3 = 19;
// const TAPE_STATE_NEXT_CLIP_SAMPLE_IDX_TRACK_4 = 20;

// buttons

export const TAPE_STATE_LIFT_BUTTON = 64;
export const TAPE_STATE_DROP_BUTTON = 65;
export const TAPE_STATE_SPLIT_BUTTON = 66;
export const TAPE_STATE_REC_BUTTON = 67;
export const TAPE_STATE_PLAY_BUTTON = 68;
export const TAPE_STATE_STOP_BUTTON = 69;
export const TAPE_STATE_LEFT_BUTTON = 70;
export const TAPE_STATE_RIGHT_BUTTON = 71;
export const TAPE_STATE_SHIFT_BUTTON = 72;
export const TAPE_STATE_LOOP_IN_BUTTON = 73;
export const TAPE_STATE_LOOP_OUT_BUTTON = 74;
export const TAPE_STATE_LOOP_CLEAR_BUTTON = 75;

// clip stuff

const MAX_NUM_CLIPS = 1_000;
const CLIP_TRACK_ID = 0;
const CLIP_START_FRAME_IDX = 1;
const CLIP_LENGTH = 2;
const CLIP_SAMPLES_START_IDX = 3;
const CLIP_STRUCT_SIZE = 4;

export interface ClipInfo {
  offset: number;
  track: number;
  samplesStartIdx: number;
  length: number;
  startFrameIdx: number;
}

export default class TapeState {
  public static new() {
    return new TapeState(
      new Float32Array<any>(new SharedArrayBuffer(128 * 4)),
      new Float32Array<any>(new SharedArrayBuffer(MAX_NUM_CLIPS * CLIP_STRUCT_SIZE * 4))
    );
  }

  public static fromStateAndClipsArrays(state: Float32Array<any>, clips: Float32Array<any>) {
    return new TapeState(state, clips);
  }

  private constructor(
    public readonly _state: Float32Array<any>,
    public readonly _clips: Float32Array<any>
  ) {}

  // tracks

  set selectedTrackIdx(value: number) {
    this._state[TAPE_STATE_SELECTED_TRACK_IDX] = value;
  }

  get selectedTrackIdx() {
    return this._state[TAPE_STATE_SELECTED_TRACK_IDX];
  }

  getGain(track: number) {
    return this._state[track];
  }

  setGain(track: number, value: number) {
    this._state[track] = value;
  }

  getNextFreeSampleIdx(track: number) {
    return this._state[TAPE_STATE_NEXT_CLIP_SAMPLE_IDX + track];
  }

  setNextFreeSampleIdx(track: number, value: number) {
    this._state[TAPE_STATE_NEXT_CLIP_SAMPLE_IDX + track] = value;
  }

  incrementNextFreeSampleIdx(track: number, n: number) {
    this._state[TAPE_STATE_NEXT_CLIP_SAMPLE_IDX + track] += n;
  }

  // tempo, time divs, etc.

  get tempo() {
    return this._state[TAPE_STATE_TEMPO];
  }

  set tempo(value: number) {
    this._state[TAPE_STATE_TEMPO] = value;
  }

  getFramesPerDiv(div = this.timeDiv) {
    const secondsPerQuarterNote = 60 / this.tempo;
    const secondsPerMeasure = 4 * secondsPerQuarterNote;
    const secondsPerDiv = secondsPerMeasure * div;
    return secondsPerDiv * SAMPLE_RATE;
  }

  get timeDiv() {
    return this._state[TAPE_STATE_TIME_DIV];
  }

  set timeDiv(value: number) {
    this._state[TAPE_STATE_TIME_DIV] = value;
  }

  // clips

  get numClips() {
    return this._state[TAPE_STATE_NUM_CLIPS];
  }

  set numClips(value: number) {
    this._state[TAPE_STATE_NUM_CLIPS] = value;
  }

  /** Allocates an new clip and returns its offset. */
  newClip() {
    return this.numClips++ * CLIP_STRUCT_SIZE;
  }

  getClipTrackId(offset: number) {
    return this._clips[offset + CLIP_TRACK_ID];
  }

  setClipTrackId(offset: number, value: number) {
    this._clips[offset + CLIP_TRACK_ID] = value;
  }

  getClipStartFrameIdx(offset: number) {
    return this._clips[offset + CLIP_START_FRAME_IDX];
  }

  setClipStartFrameIdx(offset: number, value: number) {
    this._clips[offset + CLIP_START_FRAME_IDX] = value;
  }

  getClipLength(offset: number) {
    return this._clips[offset + CLIP_LENGTH];
  }

  setClipLength(offset: number, value: number) {
    this._clips[offset + CLIP_LENGTH] = value;
  }

  getClipSamplesStartIdx(offset: number) {
    return this._clips[offset + CLIP_SAMPLES_START_IDX];
  }

  setClipSamplesStartIdx(offset: number, value: number) {
    this._clips[offset + CLIP_SAMPLES_START_IDX] = value;
  }

  getClipInfo(offset: number) {
    return {
      track: this.getClipTrackId(offset),
      startFrameIdx: this.getClipStartFrameIdx(offset),
      samplesStartIdx: this.getClipSamplesStartIdx(offset),
      length: this.getClipLength(offset),
    };
  }

  clipAt(ph: number, allowEndAtPlayhead: boolean = false): ClipInfo | null {
    if (Math.floor(ph) !== ph) {
      throw new Error('ph must be an integer!');
    }

    return this.findClip(
      ci =>
        ci.track === this.selectedTrackIdx &&
        ci.startFrameIdx <= ph &&
        (ci.startFrameIdx + ci.length > ph ||
          (allowEndAtPlayhead && ci.startFrameIdx + ci.length === ph)),
      (ci1, ci2) => ci1.offset > ci2.offset
    );
  }

  findClip(
    predicate: (clipInfo: ClipInfo) => boolean = () => true,
    isBetter: (ci1: ClipInfo, ci2: ClipInfo) => boolean = (ci1, ci2) => true
  ): ClipInfo | null {
    let bestSoFar: ClipInfo | null = null;
    this.forEachClip((trackIdx, startFrameIdx, length, samplesStartIdx, offset) => {
      const ci = { offset, track: trackIdx, samplesStartIdx, length, startFrameIdx };
      if (!predicate(ci)) {
        return;
      }
      if (!bestSoFar || isBetter(ci, bestSoFar)) {
        bestSoFar = ci;
      }
    });
    return bestSoFar;
  }

  forEachClip(
    fn: (
      trackIdx: number,
      startFrameIdx: number,
      length: number,
      samplesStartIdx: number,
      offset: number
    ) => void
  ) {
    for (let i = 0; i < this.numClips; i++) {
      const offset = i * CLIP_STRUCT_SIZE;
      const trackIdx = this.getClipTrackId(offset);
      const startFrameIdx = this.getClipStartFrameIdx(offset);
      const length = this.getClipLength(offset);
      const samplesStartIdx = this.getClipSamplesStartIdx(offset);
      fn(trackIdx, startFrameIdx, length, samplesStartIdx, offset);
    }
  }

  removeClip(offset: number) {
    this._clips.copyWithin(offset, offset + CLIP_STRUCT_SIZE, this.numClips-- * CLIP_STRUCT_SIZE);
  }

  // playhead, recording, playing, etc.

  get playhead() {
    return this._state[TAPE_STATE_PLAYHEAD];
  }

  set playhead(value: number) {
    this._state[TAPE_STATE_PLAYHEAD] = value;
  }

  get recording() {
    return this._state[TAPE_STATE_RECORDING] === 1;
  }

  set recording(value: boolean) {
    this._state[TAPE_STATE_RECORDING] = value ? 1 : 0;
  }

  get playing() {
    return this._state[TAPE_STATE_PLAYING_DIRECTION] !== 0;
  }

  get playingDirection() {
    return this._state[TAPE_STATE_PLAYING_DIRECTION];
  }

  set playingDirection(value: number) {
    this._state[TAPE_STATE_PLAYING_DIRECTION] = value;
  }

  get speed() {
    return this._state[TAPE_STATE_SPEED];
  }

  set speed(value: number) {
    this._state[TAPE_STATE_SPEED] = value;
  }

  // metronome

  set metronomeStickDirection(value: number) {
    this._state[TAPE_STATE_METRONOME_STICK_DIRECTION] = value;
  }

  get metronomeStickDirection() {
    return this._state[TAPE_STATE_METRONOME_STICK_DIRECTION];
  }

  get clickOn() {
    return this._state[TAPE_STATE_CLICK_ON] === 1;
  }

  set clickOn(value: boolean) {
    this._state[TAPE_STATE_CLICK_ON] = value ? 1 : 0;
  }

  // buttons

  get liftButtonDown() {
    return this._state[TAPE_STATE_LIFT_BUTTON] === 1;
  }

  set liftButtonDown(value: boolean) {
    this._state[TAPE_STATE_LIFT_BUTTON] = value ? 1 : 0;
  }

  get dropButtonDown() {
    return this._state[TAPE_STATE_DROP_BUTTON] === 1;
  }

  set dropButtonDown(value: boolean) {
    this._state[TAPE_STATE_DROP_BUTTON] = value ? 1 : 0;
  }

  get splitButtonDown() {
    return this._state[TAPE_STATE_SPLIT_BUTTON] === 1;
  }

  set splitButtonDown(value: boolean) {
    this._state[TAPE_STATE_SPLIT_BUTTON] = value ? 1 : 0;
  }

  get recButtonDown() {
    return this._state[TAPE_STATE_REC_BUTTON] === 1;
  }

  set recButtonDown(value: boolean) {
    this._state[TAPE_STATE_REC_BUTTON] = value ? 1 : 0;
  }

  get playButtonDown() {
    return this._state[TAPE_STATE_PLAY_BUTTON] === 1;
  }

  set playButtonDown(value: boolean) {
    this._state[TAPE_STATE_PLAY_BUTTON] = value ? 1 : 0;
  }

  get stopButtonDown() {
    return this._state[TAPE_STATE_STOP_BUTTON] === 1;
  }

  set stopButtonDown(value: boolean) {
    this._state[TAPE_STATE_STOP_BUTTON] = value ? 1 : 0;
  }

  get leftButtonDown() {
    return this._state[TAPE_STATE_LEFT_BUTTON] === 1;
  }

  set leftButtonDown(value: boolean) {
    this._state[TAPE_STATE_LEFT_BUTTON] = value ? 1 : 0;
  }

  get rightButtonDown() {
    return this._state[TAPE_STATE_RIGHT_BUTTON] === 1;
  }

  set rightButtonDown(value: boolean) {
    this._state[TAPE_STATE_RIGHT_BUTTON] = value ? 1 : 0;
  }

  get shiftButtonDown() {
    return this._state[TAPE_STATE_SHIFT_BUTTON] === 1;
  }

  set shiftButtonDown(value: boolean) {
    this._state[TAPE_STATE_SHIFT_BUTTON] = value ? 1 : 0;
  }

  get loopInButtonDown() {
    return this._state[TAPE_STATE_LOOP_IN_BUTTON] === 1;
  }

  set loopInButtonDown(value: boolean) {
    this._state[TAPE_STATE_LOOP_IN_BUTTON] = value ? 1 : 0;
  }

  get loopOutButtonDown() {
    return this._state[TAPE_STATE_LOOP_OUT_BUTTON] === 1;
  }

  set loopOutButtonDown(value: boolean) {
    this._state[TAPE_STATE_LOOP_OUT_BUTTON] = value ? 1 : 0;
  }

  get loopClearButtonDown() {
    return this._state[TAPE_STATE_LOOP_CLEAR_BUTTON] === 1;
  }

  set loopClearButtonDown(value: boolean) {
    this._state[TAPE_STATE_LOOP_CLEAR_BUTTON] = value ? 1 : 0;
  }

  // looping

  get loopOn() {
    return this._state[TAPE_STATE_LOOP_ON] === 1;
  }

  set loopOn(value: boolean) {
    this._state[TAPE_STATE_LOOP_ON] = value ? 1 : 0;
  }

  get loopInPoint() {
    return this._state[TAPE_STATE_LOOP_IN_POINT];
  }

  set loopInPoint(value: number) {
    this._state[TAPE_STATE_LOOP_IN_POINT] = value;
  }

  get loopOutPoint() {
    return this._state[TAPE_STATE_LOOP_OUT_POINT];
  }

  set loopOutPoint(value: number) {
    this._state[TAPE_STATE_LOOP_OUT_POINT] = value;
  }
}
