export function toFrequency(midiNote: number) {
  return 440 * Math.pow(2, (midiNote - 69) / 12);
}

// adapted from https://github.com/pichenettes/stmlib/blob/master/dsp/dsp.h
export function interpolatedRead(xs: Float32Array, idx: number) {
  const whole = Math.floor(idx);
  const frac = idx - whole;
  const xm1 = xs[whole - 1 < 0 ? xs.length - 1 : whole - 1];
  const x0 = xs[whole];
  const x1 = xs[(whole + 1) % xs.length];
  const x2 = xs[(whole + 2) % xs.length];
  const c = (x1 - xm1) / 2;
  const v = x0 - x1;
  const w = c + v;
  const a = w + v + (x2 - x0) / 2;
  const bNeg = w + a;
  return ((a * frac - bNeg) * frac + c) * frac + x0;
}

export function fastTanh(x: number) {
  if (x > 3) {
    return 1;
  } else if (x < -3) {
    return -1;
  } else {
    const x2 = x * x;
    return (x * (27 + x2)) / (27 + 9 * x2);
  }
}

export function clamp(v: number, min: number, max: number) {
  return Math.max(min, Math.min(v, max));
}

/**
 * Amplitude multiplier for patch `noteVel` from MIDI velocity (0–127).
 * Linear vel/127 makes medium and soft hits much quieter than they sound; loudness is roughly logarithmic,
 * so we map normalized velocity through a dB range (exponential gain), similar to a synth velocity curve.
 */
export function midiVelocityToNoteVelGain(vel: number, minDbWhenSoft = -14): number {
  const t = clamp(vel / 127, 0, 1);
  const db = minDbWhenSoft * (1 - t);
  return Math.pow(10, db / 20);
}

export function makeSharedFloat32Array(length: number): Float32Array<any> {
  return new Float32Array(new SharedArrayBuffer(length * 4));
}

export class SpeedTracker {
  readonly windowMs = 150;
  history: { pos: number; t: number }[] = [];

  addPos(pos: number) {
    this.history.push({ pos, t: performance.now() });
  }

  /** the current speed, in pixels per millisecond */
  get speed() {
    const now = performance.now();
    this.history = this.history.filter(({ t }) => now - t <= this.windowMs);

    if (this.history.length < 2) {
      return 0;
    }

    let totalDistance = 0;
    for (let idx = 1; idx < this.history.length; idx++) {
      totalDistance += Math.abs(this.history[idx].pos - this.history[idx - 1].pos);
    }

    const dt = this.history[this.history.length - 1].t - this.history[0].t;
    return totalDistance / dt;
  }
}

export function pad(n: number, numDigits = 2) {
  let s = '' + n;
  while (s.length < numDigits) {
    s = '0' + s;
  }
  return s;
}
