import { SAMPLE_RATE, SAMPLE_RATE_RECIP, TAU } from './constants';

const CLICK_SAMPLES = Math.round(0.032 * SAMPLE_RATE);
const CLICK_FREQ_WEAK = 440;
const CLICK_FREQ_DOWNBEAT = 880;
const CLICK_LEVEL = 0.65;

export class Metronome {
  private clickFramesRemaining = 0;
  private clickPhase = 0;
  private clickFreq = CLICK_FREQ_WEAK;

  click(downbeat: boolean) {
    this.clickFramesRemaining = CLICK_SAMPLES;
    this.clickPhase = 0;
    this.clickFreq = downbeat ? CLICK_FREQ_DOWNBEAT : CLICK_FREQ_WEAK;
  }

  mixInto(output: Float32Array[], outputFrameIdx: number, level: number = CLICK_LEVEL) {
    if (this.clickFramesRemaining <= 0) {
      return;
    }

    const elapsed = CLICK_SAMPLES - this.clickFramesRemaining;
    const t = elapsed / CLICK_SAMPLES;
    const env = Math.exp(-5 * t);
    const s = level * env * Math.sin(this.clickPhase);

    this.clickPhase += TAU * this.clickFreq * SAMPLE_RATE_RECIP;
    this.clickFramesRemaining--;

    for (let channel = 0; channel < output.length; channel++) {
      output[channel][outputFrameIdx] += s;
    }
  }
}
